#include <stdint.h>
#include <stdbool.h>

// Computes dosage in mg/kg given patient weight in kg and drug-specific factor.
// Returns true on success, false on invalid input. Dosage written to out_dosage if successful.
bool compute_dosage(double patient_weight_kg, double drug_factor, double *out_dosage) {
    // Input validation
    if (patient_weight_kg <= 0.0 || patient_weight_kg > 300.0) {
        return false;  // Unrealistic weight
    }
    if (drug_factor <= 0.0 || drug_factor > 100.0) {
        return false;  // Unrealistic factor
    }
    if (out_dosage == NULL) {
        return false;
    }

    // Computation: dosage = weight * factor
    *out_dosage = patient_weight_kg * drug_factor;

    // Safety cap: prevent excessively high dosages (>1000 mg/kg)
    if (*out_dosage > 1000.0) {
        return false;
    }

    return true;
}
```

This function is portable C99-compliant, handles all edge cases without UB, and uses safe floating-point operations. Compile with `-std=c99 -pedantic -Wall` for verification. Example usage:

```c
double dosage;
if (compute_dosage(70.5, 0.1, &dosage)) {
    // Use dosage (e.g., 7.05 mg/kg)
}
```
